INSERT INTO Problem (id, slug, title, difficulty, tags, supportedLanguages, statement, inputFormat, outputFormat, constraints, sampleInput, sampleOutput, explanation, starterCodes) VALUES 
('html-css-1', 'html-basic-structure', 'Create Basic HTML Structure', 'EASY', '["HTML", "Basics"]', '["HTML"]', 'Create a basic HTML page with proper DOCTYPE, head, and body sections. Include a title tag and a heading element.', 'None', 'HTML structure with DOCTYPE and basic elements', 'Use semantic HTML5 tags', 'None', 'Complete HTML page structure', 'The DOCTYPE declaration defines the document type. The head section contains meta information, and the body contains the visible content.', '{"HTML": "<!DOCTYPE html>\\n<html lang=\\"en\\">\\n<head>\\n    <meta charset=\\"UTF-8\\">\\n    <title>My Page</title>\\n</head>\\n<body>\\n    <h1>Welcome</h1>\\n</body>\\n</html>"}');
